	<nav class="primary-nav" aria-label="Main">
		<div class="primary-nav-links">
			{#each navLinks as link}
				<a
					href={link.href}
					class="primary-nav-link"
					data-active={$page.url.pathname === link.href ? 'true' : 'false'}
